// Pseudo-code: idempotent checkout acceptance (node-like pseudocode)
async function acceptCheckout(req) {
  const idempotencyKey = req.headers['Idempotency-Key']
  const shopId = req.body.shop_id
  const shard = shardRouter.forShop(shopId)

  // quick local inventory reservation in Redis (short TTL)
  const reservationToken = await redis.reserveItems(shopId, req.body.items, 60 /*sec*/)
  if (!reservationToken) throw new Error('OutOfStock')

  // write minimal receipt atomically (idempotent upsert)
  const receipt = await shard.query(`
    INSERT INTO receipts(idempotency_key, order_id, shop_id, total, items_hash, reservation_token, state)
    VALUES(?,?,?,?,?,?, 'ACCEPTED')
    ON DUPLICATE KEY UPDATE order_id=order_id /* no-op to return existing */
    RETURNING *
  `, [idempotencyKey, generateOrderId(), shopId, req.body.total, hashItems(req.body.items), reservationToken])

  // publish event for async workers
  await stream.publish('OrderCreated', { receipt_id: receipt.id, shop_id: shopId })

  return { status: 200, order_id: receipt.order_id }
}
